149→export const mobileApi = {
150→  async getJournals(cursor: string | null, limit = 10, userId?: string): Promise<CursorPage<JournalItem>> {
151→    const params = new URLSearchParams();
152→    params.set('limit', String(limit));
153→    if (cursor) {
154→      params.set('before', cursor);
155→    }
156→    if (userId) {
157→      params.set('userId', userId);
158→    }
159→
160→    return apiRequest<CursorPage<JournalItem>>(`/journals?${params.toString()}`, {
161→      method: 'GET',
162→    });
163→  },
164→
165→  async getJournalById(journalId: string, userId?: string): Promise<{ journal: JournalItem }> {
166→    const params = new URLSearchParams();
167→    if (userId) {
168→      params.set('userId', userId);
169→    }
170→
171→    const suffix = params.toString() ? `?${params.toString()}` : '';
172→    return apiRequest<{ journal: JournalItem }>(`/journal/${encodeURIComponent(journalId)}${suffix}`, {
173→      method: 'GET',
174→    });
175→  },
